import type { LocalizedTutorialContent } from '../tutorials-longform-i18n';

// Localized long-form content for one tutorial. Generated from validated
// per-locale translation JSONs; en renders from the Markdown source.
export const entry: Partial<Record<string, LocalizedTutorialContent>> = {
  "zh": {
    title: "用 Open Design 设计一个匹配你现有品牌的网站",
    summary: "一份关于 Open Design 招牌技巧的实操指南——把它指向你的线上网站，让代理抓取你的字体、配色和语气，生成一份品牌规范，然后用你的风格来设计。包含一键桌面安装，以及对 Claude Design 用量上限的坦诚评价。基于 Brendan O'Connell 的实操演示。",
    bodyHtml: "<p>本指南聚焦 Open Design 的一个招牌技巧：<strong>把它指向你现有的网站，代理会把你真实的品牌——字体、配色、语气——提炼成一份规范，然后用你的风格来设计。</strong>本文还会介绍一键桌面安装，以及为什么你会想选择一个开源替代方案的坦诚解读。它跟随 <strong>Brendan O'Connell</strong> 在<a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">他的演示</a>中进行的实操构建，经过重写并依据当前版本更新。观看上方视频可看实时操作，或继续阅读文字版。</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/generated-prototype.webp\" alt=\"在 Open Design 中生成的真实原型。\">\n<em>在预览中呈现的真实生成原型——一个深色、富有电影感的代理公司落地页。</em></p>\n<h2 id=\"what-is-open-design\">什么是 Open Design？</h2>\n<p>Open Design 是一个开源、本地优先的设计平台，它<strong>运行在你已经在用的编码代理之上</strong>——Claude Code、Codex、Cursor、Gemini、OpenCode 等等——或者用你自己的 API 密钥。它本质上是一个 Claude-Design 风格的工作区，运行在你自己的机器上，既不会被锁死在某一家厂商的云端，也没有那个工具的用量上限。它采用 Apache-2.0 许可，自带一个庞大的技能与设计系统库，并在此之上加入了媒体生成（图像、视频、音频）。</p>\n<h2 id=\"why-reach-for-an-open-alternative\">为什么要选一个开源替代方案</h2>\n<p>Brendan 的动机很具体，值得复述，因为对很多人来说这就是决定性因素。他在那个封闭的云端工具里生成了<em>一个</em>设计系统，就吃掉了<strong>大约 75% 的每周用量上限</strong>——让他被卡住，直到下一周。这个上限独立于正常套餐额度之外，这让整套工作流对真正的迭代而言几乎不可用。运行在你自己的 Claude Code（或任何）订阅上就能移除这堵墙：你不会撞上一个单独的设计上限，也不会被锁死在某一个生态里。</p>\n<h2 id=\"step-1--install-the-one-click-path\">第 1 步——安装（一键路径）</h2>\n<p>最简单的途径，也是 Brendan 推荐的，是<strong>桌面应用</strong>：前往 <a href=\"https://open-design.ai/download\">open-design.ai/download</a> 下载 macOS 或 Windows 的可执行文件。应用很快就能跑起来，并会<strong>自动检测你机器上已有的代理 CLI</strong>——Brendan 什么都没配置；它认出了他的 Claude Code 订阅，立刻就准备就绪。</p>\n<p>更喜欢用终端？从源码安装：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>打开它打印出来的本地 URL（端口是动态的——别写死）。在右侧你会看到设置：检测到的代理，外加<strong>媒体提供方</strong>（图像用 OpenAI，视频用 MiniMax，配音用 ElevenLabs）、连接器（Composio MCP），甚至还有桌面宠物。你也可以为任何提供方使用自带的密钥。</p>\n<h2 id=\"step-2--design-from-your-existing-brand\">第 2 步——从你现有的品牌出发设计</h2>\n<p>这就是值回票价的那个技巧。创建一个项目，选择<strong>高保真</strong>，然后在你的需求说明里告诉它<em>为你现有的网站</em>来设计。代理有一个<strong>网页抓取工具</strong>，所以它会去读取你的线上网站，然后从中推导出一份品牌规范。</p>\n<p>在视频里，Brendan 把它指向自己的网站，Open Design 便：</p>\n<ol>\n<li><strong>抓取页面</strong>并爬取真实内容。</li>\n<li><strong>写出一份 <code>brand-spec.md</code></strong>，捕捉到他实际使用的字体（它正确识别出了 Fig Tree）、他的配色以及他的设计取舍——“不用胶囊按钮，不用全圆角卡片，强调色克制使用，留白充裕”——再加上他的语气（“不要那种喘不过气的营销腔”）。</li>\n<li><strong>生成一份 <code>DESIGN.md</code></strong>，并用那种风格构建页面，把他现有的品牌与一套更干净的布局融合在一起。</li>\n</ol>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/workspace-home.webp\" alt=\"Open Design 工作区——描述你想要的内容并选择一种模式。\">\n<em>Open Design 工作区：描述你想构建的东西，选择一种模式，剩下的交给你的智能体完成。</em></p>\n<p>在动手构建之前，Open Design 会跑一个简短的<strong>探索表单</strong>（单页还是几页？视觉方向？是否匹配当前网站？要逼真的占位内容吗？），这样它就能锁定正确的方向。结果保留了他的标语、他的蓝色和他的字体，然后在上面叠加一套更利落的布局——多页输出，你可以逐页点击浏览。</p>\n<h2 id=\"step-3--review-the-anti-slop-self-check-and-export\">第 3 步——查看反敷衍自检并导出</h2>\n<p>在收尾时，Open Design 会跑一个<strong>反敷衍自检</strong>——Brendan 看到它确认“没有表情符号，单一字体，一处果断的点睛之笔，全文都是真实的定位文案”。这就是那道护栏，让输出不至于看起来像机器生成的。</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/motion-gallery.webp\" alt=\"Open Design 中的 HyperFrames 动效与视频画廊。\">\n<em>HyperFrames 画廊：由代码驱动的动效与视频作品，你可以复刻并二次创作。</em></p>\n<p>浏览<strong>示例</strong>和<strong>设计系统</strong>标签页寻找起点（每套设计系统都会给你一份完整可编辑的 <code>DESIGN.md</code>），满意之后，把成果导出为 HTML、PDF 或一个 ZIP。因为一切都在你自己的代理上本地运行，迭代时不会撞上任何单独的设计上限。</p>\n<h2 id=\"tips\">小贴士</h2>\n<ul>\n<li><strong>把它指向你的线上网站</strong>，以继承你真实的字体、配色和语气——这是获得贴合品牌输出的最快方式。</li>\n<li><strong>使用桌面应用</strong>走零配置路径；它会自动检测你的代理。</li>\n<li><strong>运行在你自己的 CLI 订阅上</strong>，以躲开封闭工具那个单独的每周设计上限。</li>\n<li><strong>读一读生成的 <code>brand-spec.md</code> / <code>DESIGN.md</code></strong>——它们是可编辑的文件，所以可以更正抓取出错的任何地方。</li>\n<li><strong>在提示词上多花点心思</strong>——更丰富的需求说明会带来明显更好的初稿。</li>\n</ul>\n<h2 id=\"faq\">常见问题</h2>\n<p><strong>它真的能从我现有的网站来设计吗？</strong>\n能——代理有一个网页抓取工具。告诉它为你的网站设计，它就会把你的字体、配色、布局取舍和语气爬取进一份 <code>brand-spec.md</code>，然后用那种风格来设计。</p>\n<p><strong>我必须配置我的代理吗？</strong>\n通常不用。桌面应用会自动检测已经安装的代理 CLI（Claude Code、Codex、Gemini 等等）。你也可以使用自带的密钥。</p>\n<p><strong>它有那个封闭工具的用量上限吗？</strong>\n没有单独的设计上限——生成依托于你连接的任何代理/订阅，所以你不会在做完一个设计后就被挡住。</p>\n<p><strong>它免费吗？</strong>\n这个应用是 Apache-2.0 许可下的开源软件，可免费在本地运行。你只需为你所连接的那个代理和那些提供方的模型与媒体用量付费。</p>\n<hr>\n<p><em>这篇文字指南基于 Brendan O'Connell 的实操演示。观看上方完整视频，并<a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">订阅 Brendan O'Connell</a> 获取更多开源工具拆解。</em></p>",
  },
  "ja": {
    title: "Open Design で既存ブランドに合わせたサイトをデザインする",
    summary: "Open Design の目玉テクニックを扱う実践ガイド——公開中の自社サイトに向けると、エージェントがフォント・配色・トーンをスクレイピングしてブランド仕様に落とし込み、あなたの声でデザインします。ワンクリックのデスクトップ版インストールと、Claude Design の利用上限についての率直な見解も収録。Brendan O'Connell のウォークスルーに基づく。",
    bodyHtml: "<p>このガイドは Open Design の目玉テクニックに焦点を当てます。<strong>既存のサイトに向けると、エージェントがあなたの本物のブランド——フォント・配色・トーン——を仕様に取り込み、あなたの声でデザインします。</strong>ワンクリックのデスクトップ版インストールと、なぜオープンな代替を選ぶ価値があるのかについての率直な解説も扱います。本記事は <strong>Brendan O'Connell</strong> が<a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">ウォークスルー</a>で実演する実践ビルドに沿っており、現行リリースに合わせて書き直し・更新しています。ライブ操作は上の動画を、文章版は以下をご覧ください。</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/generated-prototype.webp\" alt=\"Open Design で生成された実際のプロトタイプ。\">\n<em>プレビューに表示された実際の生成プロトタイプ——ダークで映画的なエージェンシーのランディングページ。</em></p>\n<h2 id=\"what-is-open-design\">Open Design とは？</h2>\n<p>Open Design はオープンソースでローカルファーストのデザインプラットフォームで、<strong>あなたがすでに使っているコーディングエージェントの上で動きます</strong>——Claude Code、Codex、Cursor、Gemini、OpenCode など——あるいは自前の API キーでも。本質的には Claude-Design 風のワークスペースを自分のマシン上で動かすもので、特定ベンダーのクラウドに縛られることも、そのツールの利用上限に縛られることもありません。Apache-2.0 で、スキルとデザインシステムの充実したライブラリを同梱し、その上にメディア生成（画像・動画・音声）を加えています。</p>\n<h2 id=\"why-reach-for-an-open-alternative\">なぜオープンな代替を選ぶのか</h2>\n<p>Brendan の動機は具体的で、繰り返す価値があります。多くの人にとってこれが決め手だからです。彼はクローズドなクラウドツールで<em>たった一つ</em>のデザインシステムを生成しただけで、<strong>週あたりの上限のおよそ 75% を消費</strong>してしまい——翌週まで身動きが取れなくなりました。この上限は通常のプラン枠とは別枠で、本格的な反復作業をするにはこのワークフローがほぼ使い物にならないと感じさせます。自分の Claude Code（あるいは任意の）サブスクリプションで動かせば、その壁はなくなります。別枠のデザイン上限にぶつからず、一つのエコシステムに縛られることもありません。</p>\n<h2 id=\"step-1--install-the-one-click-path\">ステップ 1——インストール（ワンクリックの道）</h2>\n<p>最も簡単な経路で、Brendan が勧めるのは<strong>デスクトップアプリ</strong>です。<a href=\"https://open-design.ai/download\">open-design.ai/download</a> にアクセスして macOS または Windows 用の実行ファイルを入手します。アプリは短時間で起動し、<strong>マシンにすでにあるエージェントの CLI を自動検出します</strong>——Brendan は何も設定しませんでした。彼の Claude Code サブスクリプションを拾い上げ、すぐに使える状態になりました。</p>\n<p>ターミナル派ですか？ソースから：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>表示されるローカル URL を開きます（ポートは動的です——固定値で書かないこと）。右側に設定があります。検出されたエージェントに加え、<strong>メディアプロバイダー</strong>（画像は OpenAI、動画は MiniMax、音声は ElevenLabs）、コネクター（Composio MCP）、さらにはデスクトップペットまで。どのプロバイダーでも自前のキーを持ち込めます。</p>\n<h2 id=\"step-2--design-from-your-existing-brand\">ステップ 2——既存ブランドからデザインする</h2>\n<p>これこそ入場料に見合うテクニックです。プロジェクトを作り、<strong>ハイフィデリティ</strong>を選び、ブリーフで<em>既存のサイト向けに</em>デザインするよう伝えます。エージェントには<strong>ウェブ取得ツール</strong>があるので、公開中のサイトを読みに行き、そこからブランド仕様を導き出します。</p>\n<p>動画では Brendan が自分のサイトに向けると、Open Design は：</p>\n<ol>\n<li><strong>ページを取得</strong>し、本物のコンテンツをスクレイピングします。</li>\n<li><strong><code>brand-spec.md</code> を書き出し</strong>、実際のフォント（Fig Tree を正しく拾いました）、配色、デザイン上の選択——「ピル型ボタンなし、完全な角丸カードなし、アクセントカラーは控えめに、余白はたっぷり」——に加え、トーン（「息せき切ったマーケティング調はなし」）を捉えます。</li>\n<li><strong><code>DESIGN.md</code> を生成</strong>し、その声でページを構築して、既存ブランドとよりすっきりしたレイアウトを融合させます。</li>\n</ol>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/workspace-home.webp\" alt=\"Open Design のワークスペース——作りたいものを記述し、モードを選びます。\">\n<em>Open Design のワークスペース：作りたいものを記述し、モードを選べば、あとはエージェントが仕上げます。</em></p>\n<p>構築の前に、Open Design は短い<strong>ディスカバリーフォーム</strong>を実行します（単一ページか数ページか？ ビジュアルの方向性は？ 現在のサイトに合わせる？ 現実的なプレースホルダーは？）。これで正しい方向を確定します。結果は彼のタグライン、青、フォントを保ちつつ、より鋭いレイアウトを上に重ねます——クリックして見て回れる複数ページの出力です。</p>\n<h2 id=\"step-3--review-the-anti-slop-self-check-and-export\">ステップ 3——アンチスロップのセルフチェックを確認してエクスポート</h2>\n<p>仕上げに、Open Design は<strong>アンチスロップのセルフチェック</strong>を実行します——Brendan は「絵文字なし、書体は一つ、決定的なあしらいが一つ、全体を通して本物のポジショニング文言」と確認されるのを見ます。これが、出力をいかにも生成物っぽく見えさせないためのガードレールです。</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/motion-gallery.webp\" alt=\"Open Design の HyperFrames モーション・動画ギャラリー。\">\n<em>HyperFrames ギャラリー：コード駆動のモーションや動画作品を、フォークしてリミックスできます。</em></p>\n<p><strong>例</strong>と<strong>デザインシステム</strong>のタブを見て出発点を探し（各デザインシステムは完全に編集可能な <code>DESIGN.md</code> を提供します）、満足したら成果物を HTML、PDF、または ZIP としてエクスポートします。すべてが自分のエージェント上でローカルに動くので、反復している間に別枠のデザイン上限にぶつかることはありません。</p>\n<h2 id=\"tips\">ヒント</h2>\n<ul>\n<li><strong>公開中のサイトに向ける</strong>と、本物のフォント・配色・トーンを引き継げます——オンブランドな出力への最速ルートです。</li>\n<li>ゼロ設定の道には<strong>デスクトップアプリを使う</strong>。エージェントを自動検出します。</li>\n<li><strong>自分の CLI サブスクリプションで動かす</strong>ことで、クローズドツールの別枠の週次デザイン上限を回避できます。</li>\n<li>生成された <strong><code>brand-spec.md</code> / <code>DESIGN.md</code> を読む</strong>——編集可能なファイルなので、スクレイプが取り違えた箇所はどこでも直せます。</li>\n<li><strong>プロンプトに少し手をかける</strong>——内容の濃いブリーフは、初稿を目に見えて良くします。</li>\n</ul>\n<h2 id=\"faq\">よくある質問</h2>\n<p><strong>本当に既存のサイトからデザインできますか？</strong>\nはい——エージェントにはウェブ取得ツールがあります。自分のサイト向けにデザインするよう伝えれば、フォント・配色・レイアウトの選択・トーンを <code>brand-spec.md</code> にスクレイピングし、その声でデザインします。</p>\n<p><strong>エージェントを設定する必要はありますか？</strong>\n通常は不要です。デスクトップアプリはすでにインストール済みのエージェント CLI（Claude Code、Codex、Gemini など）を自動検出します。自前のキーを持ち込むこともできます。</p>\n<p><strong>あのクローズドツールのような利用上限はありますか？</strong>\n別枠のデザイン上限はありません——生成は接続したエージェント／サブスクリプションに乗るので、デザインを一つ作っただけでブロックされることはありません。</p>\n<p><strong>無料ですか？</strong>\nこのアプリは Apache-2.0 のもとでのオープンソースで、ローカルで動かすのは無料です。支払うのは、接続したエージェントとプロバイダーのモデルおよびメディアの利用分だけです。</p>\n<hr>\n<p><em>この文章ガイドは Brendan O'Connell のウォークスルーに基づいています。上の完全な動画をご覧になり、さらなるオープンソースツールの解説については<a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">Brendan O'Connell をチャンネル登録</a>してください。</em></p>",
  },
  "ko": {
    title: "Open Design로 기존 브랜드에 어울리는 사이트 디자인하기",
    summary: "Open Design의 대표 기능을 다루는 실습 가이드 — 운영 중인 웹사이트를 가리키면 에이전트가 폰트, 색상, 톤을 긁어와 브랜드 사양으로 만들고, 당신의 목소리로 디자인합니다. 원클릭 데스크톱 설치와 Claude Design 사용량 한도에 대한 솔직한 평가도 포함합니다. Brendan O'Connell의 실습 영상에 기반합니다.",
    bodyHtml: "<p>이 가이드는 Open Design의 대표 기능에 초점을 맞춥니다. <strong>기존 웹사이트를 가리키면 에이전트가 당신의 진짜 브랜드 — 폰트, 색상, 톤 — 를 사양으로 끌어와 당신의 목소리로 디자인합니다.</strong> 원클릭 데스크톱 설치와, 왜 오픈 대안을 찾게 되는지에 대한 솔직한 해설도 다룹니다. 이 글은 <strong>Brendan O'Connell</strong>이 <a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">실습 영상</a>에서 진행하는 실전 빌드를 따르며, 현재 릴리스에 맞춰 다시 쓰고 업데이트했습니다. 실시간 실행은 위 영상을, 글로 된 버전은 아래를 읽어 보세요.</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/generated-prototype.webp\" alt=\"Open Design에서 생성된 실제 프로토타입.\">\n<em>미리보기에 렌더링된 실제 생성 프로토타입 — 어둡고 영화 같은 에이전시 랜딩 페이지.</em></p>\n<h2 id=\"what-is-open-design\">Open Design이란?</h2>\n<p>Open Design은 오픈소스이자 로컬 우선의 디자인 플랫폼으로, <strong>이미 쓰고 있는 코딩 에이전트 위에서 동작합니다</strong> — Claude Code, Codex, Cursor, Gemini, OpenCode 등 — 또는 자신의 API 키로요. 본질적으로 Claude-Design 스타일의 작업 공간을 자기 컴퓨터에서 돌리는 것으로, 특정 벤더의 클라우드에 묶이지도, 그 도구의 사용량 한도에 묶이지도 않습니다. Apache-2.0 라이선스이며, 방대한 스킬과 디자인 시스템 라이브러리를 기본 제공하고, 그 위에 미디어 생성(이미지, 동영상, 오디오)을 더합니다.</p>\n<h2 id=\"why-reach-for-an-open-alternative\">왜 오픈 대안을 찾는가</h2>\n<p>Brendan의 동기는 구체적이고 다시 짚을 만합니다. 많은 사람에게 이것이 결정적 요인이기 때문입니다. 그는 폐쇄형 클라우드 도구에서 <em>단 하나의</em> 디자인 시스템을 생성했을 뿐인데 <strong>주간 한도의 약 75%를 소진</strong>했고 — 다음 주까지 발이 묶였습니다. 이 한도는 일반 요금제 할당량과 별개라서, 진짜 반복 작업을 하기에는 워크플로가 사실상 쓸 수 없을 지경으로 느껴집니다. 자신의 Claude Code(또는 어떤) 구독으로 돌리면 그 벽이 사라집니다. 별도의 디자인 한도에 부딪히지 않고, 하나의 생태계에 묶이지도 않습니다.</p>\n<h2 id=\"step-1--install-the-one-click-path\">1단계 — 설치 (원클릭 경로)</h2>\n<p>가장 쉬운 길이자 Brendan이 권하는 것은 <strong>데스크톱 앱</strong>입니다. <a href=\"https://open-design.ai/download\">open-design.ai/download</a>에 가서 macOS 또는 Windows용 실행 파일을 받으세요. 앱은 금세 구동되며, <strong>이미 컴퓨터에 있는 에이전트 CLI를 자동 감지합니다</strong> — Brendan은 아무것도 설정하지 않았고, 그의 Claude Code 구독을 인식해 바로 쓸 준비가 됐습니다.</p>\n<p>터미널을 선호하나요? 소스에서:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>출력되는 로컬 URL을 여세요(포트는 동적입니다 — 하드코딩하지 마세요). 오른쪽에 설정이 있습니다. 감지된 에이전트와 함께 <strong>미디어 제공자</strong>(이미지는 OpenAI, 동영상은 MiniMax, 음성은 ElevenLabs), 커넥터(Composio MCP), 심지어 데스크톱 펫까지 있습니다. 어떤 제공자든 자신의 키를 가져와 쓸 수도 있습니다.</p>\n<h2 id=\"step-2--design-from-your-existing-brand\">2단계 — 기존 브랜드에서 디자인하기</h2>\n<p>이것이 입장료가 아깝지 않은 기능입니다. 프로젝트를 만들고 <strong>고충실도</strong>를 선택한 뒤, 브리프에서 <em>기존 사이트를 위해</em> 디자인하라고 알려 주세요. 에이전트에는 <strong>웹 가져오기 도구</strong>가 있어서, 운영 중인 사이트를 읽으러 가 거기서 브랜드 사양을 도출합니다.</p>\n<p>영상에서 Brendan이 자신의 사이트를 가리키자 Open Design은:</p>\n<ol>\n<li><strong>페이지를 가져오고</strong> 실제 콘텐츠를 긁어옵니다.</li>\n<li><strong><code>brand-spec.md</code>를 작성</strong>해, 그가 실제로 쓰는 폰트(Fig Tree를 정확히 잡아냈습니다), 색상, 디자인 선택 — “알약 모양 버튼 금지, 완전 둥근 카드 금지, 강조색은 절제해서, 여백은 넉넉히” — 그리고 톤(“숨 가쁜 마케팅 어조 금지”)까지 포착합니다.</li>\n<li><strong><code>DESIGN.md</code>를 생성</strong>하고 그 목소리로 페이지를 구축해, 기존 브랜드와 더 깔끔한 레이아웃을 어우러지게 합니다.</li>\n</ol>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/workspace-home.webp\" alt=\"Open Design 워크스페이스 — 원하는 것을 설명하고 모드를 선택하세요.\">\n<em>Open Design 워크스페이스: 만들고 싶은 것을 설명하고 모드를 선택하면 나머지는 에이전트가 처리합니다.</em></p>\n<p>구축에 앞서 Open Design은 짧은 <strong>디스커버리 양식</strong>을 실행합니다(한 페이지인가 몇 페이지인가? 비주얼 방향은? 현재 사이트에 맞출까? 사실적인 플레이스홀더로? ). 그래서 올바른 방향을 확정합니다. 결과물은 그의 태그라인, 파란색, 폰트를 유지하면서 그 위에 더 또렷한 레이아웃을 얹습니다 — 클릭해 둘러볼 수 있는 다중 페이지 출력입니다.</p>\n<h2 id=\"step-3--review-the-anti-slop-self-check-and-export\">3단계 — 안티슬롭 자가 점검을 확인하고 내보내기</h2>\n<p>마무리하면서 Open Design은 <strong>안티슬롭 자가 점검</strong>을 실행합니다 — Brendan은 “이모지 없음, 서체 하나, 결정적인 장식 하나, 전반에 걸쳐 진짜 포지셔닝 카피”라고 확인하는 것을 봅니다. 이것이 출력물이 생성물처럼 보이지 않게 막아 주는 가드레일입니다.</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/motion-gallery.webp\" alt=\"Open Design의 HyperFrames 모션·비디오 갤러리.\">\n<em>HyperFrames 갤러리: 코드 기반의 모션과 비디오 작품을 포크하고 리믹스할 수 있습니다.</em></p>\n<p><strong>예시</strong>와 <strong>디자인 시스템</strong> 탭을 둘러보며 출발점을 찾고(각 디자인 시스템은 완전히 편집 가능한 <code>DESIGN.md</code>를 제공합니다), 마음에 들면 결과물을 HTML, PDF, 또는 ZIP으로 내보내세요. 모든 것이 자신의 에이전트 위에서 로컬로 돌기 때문에, 반복하는 동안 부딪힐 별도의 디자인 한도가 없습니다.</p>\n<h2 id=\"tips\">팁</h2>\n<ul>\n<li><strong>운영 중인 사이트를 가리키면</strong> 진짜 폰트, 색상, 톤을 물려받습니다 — 온브랜드 출력으로 가는 가장 빠른 길입니다.</li>\n<li>제로 설정 경로를 위해 <strong>데스크톱 앱을 사용하세요</strong>. 에이전트를 자동 감지합니다.</li>\n<li><strong>자신의 CLI 구독으로 돌려</strong> 폐쇄형 도구의 별도 주간 디자인 한도를 피하세요.</li>\n<li>생성된 <strong><code>brand-spec.md</code> / <code>DESIGN.md</code>를 읽으세요</strong> — 편집 가능한 파일이라, 스크레이프가 잘못 잡은 부분은 무엇이든 고칠 수 있습니다.</li>\n<li><strong>프롬프트에 조금 공을 들이세요</strong> — 더 풍부한 브리프는 눈에 띄게 더 나은 초안을 만들어 냅니다.</li>\n</ul>\n<h2 id=\"faq\">자주 묻는 질문</h2>\n<p><strong>정말 제 기존 웹사이트에서 디자인할 수 있나요?</strong>\n네 — 에이전트에는 웹 가져오기 도구가 있습니다. 당신의 사이트를 위해 디자인하라고 알려 주면 폰트, 색상, 레이아웃 선택, 톤을 <code>brand-spec.md</code>로 긁어와 그 목소리로 디자인합니다.</p>\n<p><strong>에이전트를 설정해야 하나요?</strong>\n대개는 아닙니다. 데스크톱 앱은 이미 설치된 에이전트 CLI(Claude Code, Codex, Gemini 등)를 자동 감지합니다. 자신의 키를 가져와 쓸 수도 있습니다.</p>\n<p><strong>폐쇄형 도구의 사용량 한도가 있나요?</strong>\n별도의 디자인 한도는 없습니다 — 생성은 연결한 에이전트/구독에 얹혀 가므로, 디자인 하나를 만든 뒤 막히는 일이 없습니다.</p>\n<p><strong>무료인가요?</strong>\n이 앱은 Apache-2.0 하의 오픈소스이며 로컬로 돌리는 것은 무료입니다. 연결한 에이전트와 제공자의 모델 및 미디어 사용분에 대해서만 비용을 냅니다.</p>\n<hr>\n<p><em>이 글 가이드는 Brendan O'Connell의 실습 영상에 기반합니다. 위의 전체 영상을 보시고, 더 많은 오픈소스 도구 분석을 위해 <a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">Brendan O'Connell을 구독</a>하세요.</em></p>",
  },
  "de": {
    title: "Mit Open Design eine Website gestalten, die zu deiner bestehenden Marke passt",
    summary: "Eine praxisnahe Anleitung zum herausragenden Kniff in Open Design — richte es auf deine Live-Website, und der Agent zieht deine Schriften, Farben und deinen Tonfall in eine Markenspezifikation und gestaltet dann in deiner Stimme. Inklusive der Ein-Klick-Desktop-Installation und einer ehrlichen Einschätzung zu den Nutzungsgrenzen von Claude Design. Basierend auf der Anleitung von Brendan O'Connell.",
    bodyHtml: "<p>Diese Anleitung konzentriert sich auf einen herausragenden Open-Design-Kniff: <strong>Richte es auf deine bestehende Website, und der Agent zieht deine echte Marke — Schriften, Farben, Tonfall — in eine Spezifikation und gestaltet dann in deiner Stimme.</strong> Außerdem geht es um die Ein-Klick-Desktop-Installation und eine ehrliche Einschätzung, warum du zu einer offenen Alternative greifen würdest. Sie folgt dem praxisnahen Aufbau, den <strong>Brendan O'Connell</strong> in <a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">seiner Anleitung</a> durchführt, neu geschrieben und auf den aktuellen Release gebracht. Schau dir das Video oben für den Live-Durchlauf an oder lies weiter für die schriftliche Fassung.</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/generated-prototype.webp\" alt=\"Ein echter, in Open Design generierter Prototyp.\">\n<em>Ein echter generierter Prototyp in der Vorschau – eine dunkle, cineastische Agentur-Landingpage.</em></p>\n<h2 id=\"what-is-open-design\">Was ist Open Design?</h2>\n<p>Open Design ist eine quelloffene, lokal-first arbeitende Design-Plattform, die <strong>auf dem Coding-Agenten läuft, den du ohnehin schon nutzt</strong> — Claude Code, Codex, Cursor, Gemini, OpenCode und mehr — oder mit deinem eigenen API-Schlüssel. Im Kern ist es ein Arbeitsbereich im Stil von Claude Design, den du auf deiner eigenen Maschine betreibst, ohne in der Cloud eines einzelnen Anbieters festzustecken und ohne dessen Nutzungsobergrenzen. Es steht unter Apache-2.0, bringt eine umfangreiche Bibliothek an Skills und Designsystemen mit und ergänzt das Ganze um Medienerzeugung (Bild, Video, Audio).</p>\n<h2 id=\"why-reach-for-an-open-alternative\">Warum zu einer offenen Alternative greifen</h2>\n<p>Brendans Motivation ist konkret und es lohnt sich, sie zu wiederholen, weil sie für viele der entscheidende Faktor ist. Er erzeugte ein <em>einziges</em> Designsystem im geschlossenen Cloud-Tool, und es fraß <strong>~75 % seines Wochenlimits</strong> — und ließ ihn bis zur nächsten Woche festhängen. Dieses Limit ist getrennt vom normalen Tarifkontingent, was den Workflow für echtes Iterieren grenzwertig unbrauchbar wirken lässt. Wenn du auf deinem eigenen Claude-Code- (oder einem beliebigen) Abo läufst, fällt diese Wand weg: Du stößt nicht an eine separate Design-Obergrenze und bist nicht in ein Ökosystem eingesperrt.</p>\n<h2 id=\"step-1--install-the-one-click-path\">Schritt 1 — Installieren (der Ein-Klick-Weg)</h2>\n<p>Der einfachste Weg, und der, den Brendan empfiehlt, ist die <strong>Desktop-App</strong>: Geh zu <a href=\"https://open-design.ai/download\">open-design.ai/download</a> und hol dir die ausführbare Datei für macOS oder Windows. Die App ist in kurzer Zeit einsatzbereit und <strong>erkennt automatisch die Agent-CLIs, die schon auf deiner Maschine sind</strong> — Brendan hat nichts konfiguriert; sie nahm sein Claude-Code-Abo auf und war startklar.</p>\n<p>Lieber das Terminal? Aus dem Quellcode:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Öffne die lokale URL, die ausgegeben wird (ein dynamischer Port — schreib keinen fest). Rechts findest du Einstellungen: die erkannten Agenten sowie <strong>Medienanbieter</strong> (OpenAI für Bild, MiniMax für Video, ElevenLabs für Stimme), Konnektoren (Composio MCP) und sogar Desktop-Haustiere. Du kannst für jeden Anbieter auch deinen eigenen Schlüssel mitbringen.</p>\n<h2 id=\"step-2--design-from-your-existing-brand\">Schritt 2 — Aus deiner bestehenden Marke gestalten</h2>\n<p>Das ist der Kniff, der den Eintrittspreis wert ist. Erstelle ein Projekt, wähle <strong>High Fidelity</strong>, und sag ihm in deinem Briefing, es solle <em>für deine bestehende Website</em> gestalten. Der Agent verfügt über ein <strong>Web-Fetch-Werkzeug</strong>, also liest er deine Live-Website und leitet daraus eine Markenspezifikation ab.</p>\n<p>Im Video richtet Brendan es auf seine eigene Seite, und Open Design:</p>\n<ol>\n<li><strong>holt die Seite ab</strong> und liest die echten Inhalte aus.</li>\n<li><strong>schreibt eine <code>brand-spec.md</code></strong>, die seine tatsächliche Schrift erfasst (es erkannte korrekt Fig Tree), seine Farbe und seine Designentscheidungen — „keine Pillen-Buttons, keine vollständig abgerundeten Karten, Akzentfarbe sparsam eingesetzt, großzügiger Weißraum“ — plus seinen Tonfall („kein atemloses Marketing“).</li>\n<li><strong>erzeugt eine <code>DESIGN.md</code></strong> und baut die Seite in dieser Stimme, indem es seine bestehende Marke mit einem klareren Layout verbindet.</li>\n</ol>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/workspace-home.webp\" alt=\"Der Open Design-Arbeitsbereich — beschreibe, was du möchtest, und wähle einen Modus.\">\n<em>Der Open Design-Arbeitsbereich: Beschreibe, was du erstellen willst, wähle einen Modus, und dein Agent erledigt den Rest.</em></p>\n<p>Vor dem Bauen lässt Open Design ein kurzes <strong>Discovery-Formular</strong> durchlaufen (eine Seite oder ein paar Seiten? visuelle Richtung? die aktuelle Seite treffen? realistische Platzhalter?), damit es die richtige Richtung festzurrt. Das Ergebnis behält seinen Slogan, sein Blau und seine Schrift und legt darüber ein schärferes Layout — eine mehrseitige Ausgabe, durch die du klicken kannst.</p>\n<h2 id=\"step-3--review-the-anti-slop-self-check-and-export\">Schritt 3 — Den Anti-Slop-Selbstcheck prüfen und exportieren</h2>\n<p>Zum Abschluss lässt Open Design einen <strong>Anti-Slop-Selbstcheck</strong> laufen — Brendan sieht, wie er „keine Emojis, eine Schriftart, ein entschlossener Akzent, durchgehend echte Positionierungstexte“ bestätigt. Das ist die Leitplanke, die verhindert, dass die Ausgabe generiert aussieht.</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/motion-gallery.webp\" alt=\"Die HyperFrames-Galerie für Motion und Video in Open Design.\">\n<em>Die HyperFrames-Galerie: code-getriebene Motion- und Video-Stücke, die du forken und remixen kannst.</em></p>\n<p>Durchstöbere die Tabs <strong>Beispiele</strong> und <strong>Designsysteme</strong> nach Startpunkten (jedes Designsystem gibt dir eine vollständig bearbeitbare <code>DESIGN.md</code>), und wenn du zufrieden bist, exportiere das Artefakt als HTML, PDF oder ZIP. Weil alles lokal auf deinem eigenen Agenten läuft, gibt es keine separate Design-Obergrenze, an die du beim Iterieren stößt.</p>\n<h2 id=\"tips\">Tipps</h2>\n<ul>\n<li><strong>Richte es auf deine Live-Seite</strong>, um deine echten Schriften, Farben und deinen Tonfall zu erben — der schnellste Weg zu markengerechter Ausgabe.</li>\n<li><strong>Nutze die Desktop-App</strong> für den Weg ohne Konfiguration; sie erkennt deinen Agenten automatisch.</li>\n<li><strong>Lauf auf deinem eigenen CLI-Abo</strong>, um der separaten wöchentlichen Design-Obergrenze geschlossener Tools auszuweichen.</li>\n<li><strong>Lies die erzeugte <code>brand-spec.md</code> / <code>DESIGN.md</code></strong> — es sind bearbeitbare Dateien, also korrigiere alles, was der Scrape falsch erfasst hat.</li>\n<li><strong>Investiere ein wenig in den Prompt</strong> — ein reichhaltigeres Briefing liefert einen spürbar besseren ersten Wurf.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Kann es wirklich aus meiner bestehenden Website gestalten?</strong>\nJa — der Agent hat ein Web-Fetch-Werkzeug. Sag ihm, er soll für deine Seite gestalten, und er liest deine Schriften, Farben, Layout-Entscheidungen und deinen Tonfall in eine <code>brand-spec.md</code> aus und gestaltet dann in dieser Stimme.</p>\n<p><strong>Muss ich meinen Agenten konfigurieren?</strong>\nMeist nicht. Die Desktop-App erkennt die bereits installierten Agent-CLIs automatisch (Claude Code, Codex, Gemini und mehr). Du kannst auch deinen eigenen Schlüssel mitbringen.</p>\n<p><strong>Hat es die Nutzungsgrenzen des geschlossenen Tools?</strong>\nKeine separate Design-Obergrenze — die Erzeugung läuft über den Agenten/das Abo, das du verbindest, sodass du nach einem Design nicht blockiert wirst.</p>\n<p><strong>Ist es kostenlos?</strong>\nDie App ist Open Source unter Apache-2.0 und kostenlos lokal lauffähig. Du zahlst nur für die Modell- und Mediennutzung des jeweiligen Agenten und der Anbieter, die du verbindest.</p>\n<hr>\n<p><em>Diese schriftliche Anleitung basiert auf der Anleitung von Brendan O'Connell. Schau dir das vollständige Video oben an und <a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">abonniere Brendan O'Connell</a> für weitere Analysen quelloffener Tools.</em></p>",
  },
  "fr": {
    title: "Concevoir avec Open Design un site qui colle à votre marque existante",
    summary: "Un guide pratique sur l'astuce phare d'Open Design — pointez-le vers votre site en ligne et l'agent récupère vos polices, vos couleurs et votre ton dans une spécification de marque, puis conçoit dans votre voix. Inclut l'installation bureau en un clic et un avis franc sur les limites d'usage de Claude Design. D'après la démonstration de Brendan O'Connell.",
    bodyHtml: "<p>Ce guide se concentre sur une astuce phare d'Open Design : <strong>pointez-le vers votre site existant et l'agent tire votre véritable marque — polices, couleurs, ton — dans une spécification, puis conçoit dans votre voix.</strong> Il couvre aussi l'installation bureau en un clic et un regard franc sur les raisons de se tourner vers une alternative ouverte. Il suit la réalisation pratique que <strong>Brendan O'Connell</strong> mène dans <a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">sa démonstration</a>, réécrite et mise à jour pour la version actuelle. Regardez la vidéo ci-dessus pour le déroulé en direct, ou poursuivez la lecture pour la version écrite.</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/generated-prototype.webp\" alt=\"Un véritable prototype généré dans Open Design.\">\n<em>Un véritable prototype généré, rendu dans l'aperçu — une landing page d'agence sombre et cinématographique.</em></p>\n<h2 id=\"what-is-open-design\">Qu'est-ce qu'Open Design ?</h2>\n<p>Open Design est une plateforme de conception open source et local-first qui tourne <strong>par-dessus l'agent de code que vous utilisez déjà</strong> — Claude Code, Codex, Cursor, Gemini, OpenCode et d'autres — ou avec votre propre clé API. C'est en somme un espace de travail à la Claude Design que vous exécutez sur votre propre machine, sans être enfermé dans le cloud d'un seul fournisseur ni soumis aux plafonds d'usage de cet outil. Il est sous Apache-2.0, livré avec une vaste bibliothèque de skills et de systèmes de design, et y ajoute la génération de médias (image, vidéo, audio).</p>\n<h2 id=\"why-reach-for-an-open-alternative\">Pourquoi se tourner vers une alternative ouverte</h2>\n<p>La motivation de Brendan est concrète et mérite d'être répétée, car c'est le facteur décisif pour beaucoup. Il a généré un <em>seul</em> système de design dans l'outil cloud fermé, et cela a englouti <strong>environ 75 % de sa limite hebdomadaire</strong> — le laissant coincé jusqu'à la semaine suivante. Cette limite est distincte du quota normal de l'abonnement, ce qui rend le flux de travail quasi inutilisable pour une vraie itération. Tourner sur votre propre abonnement Claude Code (ou tout autre) supprime ce mur : vous ne heurtez pas de plafond de design séparé et vous n'êtes pas enfermé dans un seul écosystème.</p>\n<h2 id=\"step-1--install-the-one-click-path\">Étape 1 — Installer (la voie en un clic)</h2>\n<p>La voie la plus simple, et celle que recommande Brendan, c'est l'<strong>application de bureau</strong> : rendez-vous sur <a href=\"https://open-design.ai/download\">open-design.ai/download</a> et récupérez l'exécutable pour macOS ou Windows. L'application est opérationnelle en peu de temps et <strong>détecte automatiquement les CLI d'agents déjà présentes sur votre machine</strong> — Brendan n'a rien configuré ; elle a repéré son abonnement Claude Code et était prête à l'emploi.</p>\n<p>Vous préférez le terminal ? Depuis les sources :</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Ouvrez l'URL locale qu'il affiche (un port dynamique — n'en codez aucun en dur). À droite, vous trouverez les réglages : les agents détectés, ainsi que les <strong>fournisseurs de médias</strong> (OpenAI pour l'image, MiniMax pour la vidéo, ElevenLabs pour la voix), des connecteurs (Composio MCP), et même des animaux de bureau. Vous pouvez aussi apporter votre propre clé pour n'importe quel fournisseur.</p>\n<h2 id=\"step-2--design-from-your-existing-brand\">Étape 2 — Concevoir à partir de votre marque existante</h2>\n<p>Voilà l'astuce qui vaut à elle seule le prix du billet. Créez un projet, choisissez <strong>haute fidélité</strong>, et dans votre brief, dites-lui de concevoir <em>pour votre site existant</em>. L'agent dispose d'un <strong>outil de récupération web</strong>, il va donc lire votre site en ligne, puis en dériver une spécification de marque.</p>\n<p>Dans la vidéo, Brendan le pointe vers son propre site et Open Design :</p>\n<ol>\n<li><strong>récupère la page</strong> et en extrait le contenu réel.</li>\n<li><strong>rédige un <code>brand-spec.md</code></strong> qui capture sa police réelle (il a correctement repéré Fig Tree), sa couleur et ses choix de design — « pas de boutons en pilule, pas de cartes entièrement arrondies, couleur d'accent employée avec parcimonie, espaces blancs généreux » — plus son ton (« pas de marketing haletant »).</li>\n<li><strong>génère un <code>DESIGN.md</code></strong> et construit la page dans cette voix, en mêlant sa marque existante à une mise en page plus nette.</li>\n</ol>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/workspace-home.webp\" alt=\"L'espace de travail Open Design — décrivez ce que vous voulez et choisissez un mode.\">\n<em>L'espace de travail Open Design : décrivez ce que vous voulez créer, choisissez un mode, et votre agent fait le reste.</em></p>\n<p>Avant de construire, Open Design fait passer un court <strong>formulaire de découverte</strong> (une page ou quelques pages ? direction visuelle ? coller au site actuel ? des espaces réservés réalistes ?) afin de verrouiller la bonne direction. Le résultat conserve son slogan, son bleu et sa police, puis y superpose une mise en page plus tranchée — une sortie multipage que vous pouvez parcourir au clic.</p>\n<h2 id=\"step-3--review-the-anti-slop-self-check-and-export\">Étape 3 — Vérifier l'auto-contrôle anti-slop et exporter</h2>\n<p>En terminant, Open Design exécute un <strong>auto-contrôle anti-slop</strong> — Brendan le voit confirmer « pas d'émojis, une seule police, une touche décisive, du texte de positionnement réel d'un bout à l'autre ». C'est le garde-fou qui empêche le résultat d'avoir l'air généré.</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/motion-gallery.webp\" alt=\"La galerie de motion et de vidéo HyperFrames dans Open Design.\">\n<em>La galerie HyperFrames : des créations de motion et de vidéo pilotées par le code, à forker et à remixer.</em></p>\n<p>Parcourez les onglets <strong>exemples</strong> et <strong>systèmes de design</strong> pour trouver des points de départ (chaque système de design vous fournit un <code>DESIGN.md</code> entièrement éditable), et quand vous êtes satisfait, exportez l'artefact en HTML, PDF ou ZIP. Comme tout tourne localement sur votre propre agent, il n'y a aucun plafond de design séparé à heurter pendant que vous itérez.</p>\n<h2 id=\"tips\">Conseils</h2>\n<ul>\n<li><strong>Pointez-le vers votre site en ligne</strong> pour hériter de vos vraies polices, couleurs et de votre ton — la voie la plus rapide vers un résultat fidèle à la marque.</li>\n<li><strong>Utilisez l'application de bureau</strong> pour la voie sans configuration ; elle détecte automatiquement votre agent.</li>\n<li><strong>Tournez sur votre propre abonnement CLI</strong> pour esquiver le plafond hebdomadaire de design distinct des outils fermés.</li>\n<li><strong>Lisez les <code>brand-spec.md</code> / <code>DESIGN.md</code> générés</strong> — ce sont des fichiers éditables, alors corrigez tout ce que la récupération a mal saisi.</li>\n<li><strong>Investissez un peu dans le prompt</strong> — un brief plus riche produit une première version nettement meilleure.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Peut-il vraiment concevoir à partir de mon site existant ?</strong>\nOui — l'agent dispose d'un outil de récupération web. Dites-lui de concevoir pour votre site et il extrait vos polices, couleurs, choix de mise en page et ton dans un <code>brand-spec.md</code>, puis conçoit dans cette voix.</p>\n<p><strong>Dois-je configurer mon agent ?</strong>\nEn général non. L'application de bureau détecte automatiquement les CLI d'agents déjà installées (Claude Code, Codex, Gemini et plus). Vous pouvez aussi apporter votre propre clé.</p>\n<p><strong>A-t-il les limites d'usage de l'outil fermé ?</strong>\nPas de plafond de design séparé — la génération s'appuie sur l'agent/l'abonnement que vous connectez, vous n'êtes donc pas bloqué après un seul design.</p>\n<p><strong>Est-ce gratuit ?</strong>\nL'application est open source sous Apache-2.0 et gratuite à exécuter localement. Vous ne payez que l'usage du modèle et des médias de l'agent et des fournisseurs que vous connectez.</p>\n<hr>\n<p><em>Ce guide écrit s'appuie sur la démonstration de Brendan O'Connell. Regardez la vidéo complète ci-dessus, et <a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">abonnez-vous à Brendan O'Connell</a> pour d'autres décryptages d'outils open source.</em></p>",
  },
  "ru": {
    title: "Спроектируйте сайт в духе вашего бренда с помощью Open Design",
    summary: "Практическое руководство по фирменному приёму Open Design — наведите его на ваш действующий сайт, и агент соберёт ваши шрифты, цвета и тон в спецификацию бренда, а затем спроектирует в вашем стиле. Включает установку настольного приложения в один клик и честную оценку лимитов использования Claude Design. По мотивам разбора Brendan O'Connell.",
    bodyHtml: "<p>Это руководство посвящено фирменному приёму Open Design: <strong>наведите его на ваш существующий сайт, и агент вытянет ваш настоящий бренд — шрифты, цвета, тон — в спецификацию, а затем спроектирует в вашем стиле.</strong> Также рассматривается установка настольного приложения в один клик и честный взгляд на то, почему стоит обратиться к открытой альтернативе. Оно следует практической сборке, которую <strong>Brendan O'Connell</strong> проводит в <a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">своём разборе</a>, переписанной и приведённой в соответствие с текущим релизом. Смотрите видео выше для живого прогона или читайте дальше — текстовую версию.</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/generated-prototype.webp\" alt=\"Реальный прототип, сгенерированный в Open Design.\">\n<em>Реальный сгенерированный прототип в предпросмотре — тёмная, кинематографичная лендинг-страница агентства.</em></p>\n<h2 id=\"what-is-open-design\">Что такое Open Design?</h2>\n<p>Open Design — это открытая, ориентированная на локальную работу платформа для дизайна, которая работает <strong>поверх агента для кодинга, которым вы уже пользуетесь</strong> — Claude Code, Codex, Cursor, Gemini, OpenCode и других — или с вашим собственным ключом API. По сути это рабочее пространство в стиле Claude Design, которое вы запускаете на собственной машине, не будучи привязанным к облаку одного поставщика и без его лимитов использования. Оно под лицензией Apache-2.0, поставляется с обширной библиотекой навыков и дизайн-систем и добавляет сверху генерацию медиа (изображения, видео, аудио).</p>\n<h2 id=\"why-reach-for-an-open-alternative\">Зачем обращаться к открытой альтернативе</h2>\n<p>Мотивация Brendan конкретна, и её стоит повторить, потому что для многих это решающий фактор. Он сгенерировал <em>одну</em> дизайн-систему в закрытом облачном инструменте, и это съело <strong>~75 % его недельного лимита</strong> — оставив его в тупике до следующей недели. Этот лимит отделён от обычного квоты тарифа, из-за чего рабочий процесс кажется почти непригодным для реальной итеративной работы. Запуск на вашей собственной подписке Claude Code (или любой другой) убирает эту стену: вы не упираетесь в отдельный лимит на дизайн и не заперты в одной экосистеме.</p>\n<h2 id=\"step-1--install-the-one-click-path\">Шаг 1 — Установка (путь в один клик)</h2>\n<p>Самый простой путь, который рекомендует Brendan, — это <strong>настольное приложение</strong>: зайдите на <a href=\"https://open-design.ai/download\">open-design.ai/download</a> и возьмите исполняемый файл для macOS или Windows. Приложение запускается за короткое время и <strong>автоматически обнаруживает CLI агентов, уже имеющиеся на вашей машине</strong> — Brendan ничего не настраивал; оно подхватило его подписку Claude Code и было готово к работе.</p>\n<p>Предпочитаете терминал? Из исходников:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Откройте локальный URL, который оно выведет (порт динамический — не прописывайте его жёстко). Справа вы найдёте настройки: обнаруженные агенты, а также <strong>поставщиков медиа</strong> (OpenAI для изображений, MiniMax для видео, ElevenLabs для голоса), коннекторы (Composio MCP) и даже настольных питомцев. Вы также можете подключить собственный ключ для любого поставщика.</p>\n<h2 id=\"step-2--design-from-your-existing-brand\">Шаг 2 — Проектирование на основе вашего существующего бренда</h2>\n<p>Это и есть приём, ради которого стоит платить за вход. Создайте проект, выберите <strong>высокую детализацию</strong> и в брифе скажите ему проектировать <em>для вашего существующего сайта</em>. У агента есть <strong>инструмент веб-выборки</strong>, поэтому он отправится читать ваш действующий сайт, а затем выведет из него спецификацию бренда.</p>\n<p>В видео Brendan наводит его на свой собственный сайт, и Open Design:</p>\n<ol>\n<li><strong>Получает страницу</strong> и считывает реальное содержимое.</li>\n<li><strong>Пишет <code>brand-spec.md</code></strong>, фиксируя его фактический шрифт (он правильно распознал Fig Tree), его цвет и его дизайнерские решения — «никаких кнопок-пилюль, никаких полностью скруглённых карточек, акцентный цвет используется сдержанно, щедрые пробелы» — плюс его тон («без захлёбывающегося маркетинга»).</li>\n<li><strong>Генерирует <code>DESIGN.md</code></strong> и строит страницу в этом стиле, сочетая его существующий бренд с более чистой компоновкой.</li>\n</ol>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/workspace-home.webp\" alt=\"Рабочее пространство Open Design — опишите, что вам нужно, и выберите режим.\">\n<em>Рабочее пространство Open Design: опишите, что хотите создать, выберите режим, а остальное сделает ваш агент.</em></p>\n<p>Перед сборкой Open Design прогоняет короткую <strong>форму обнаружения</strong> (одна страница или несколько? визуальное направление? соответствовать текущему сайту? реалистичные заглушки?), чтобы зафиксировать верное направление. Результат сохраняет его слоган, его синий цвет и его шрифт, а затем накладывает поверх более чёткую компоновку — многостраничный вывод, по которому можно пройтись кликами.</p>\n<h2 id=\"step-3--review-the-anti-slop-self-check-and-export\">Шаг 3 — Просмотрите самопроверку против «шлака» и экспортируйте</h2>\n<p>Завершая работу, Open Design выполняет <strong>самопроверку против «шлака»</strong> — Brendan видит, как она подтверждает: «никаких эмодзи, один шрифт, один решительный штрих, настоящий позиционирующий текст повсюду». Это и есть ограждение, которое не даёт результату выглядеть сгенерированным.</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/motion-gallery.webp\" alt=\"Галерея анимации и видео HyperFrames в Open Design.\">\n<em>Галерея HyperFrames: анимационные и видеоработы на основе кода, которые можно форкнуть и переработать.</em></p>\n<p>Просмотрите вкладки <strong>примеры</strong> и <strong>дизайн-системы</strong> в поисках отправных точек (каждая дизайн-система даёт вам полностью редактируемый <code>DESIGN.md</code>), и когда останетесь довольны, экспортируйте артефакт как HTML, PDF или ZIP. Поскольку всё работает локально на вашем собственном агенте, во время итераций нет отдельного лимита на дизайн, в который можно упереться.</p>\n<h2 id=\"tips\">Советы</h2>\n<ul>\n<li><strong>Наведите его на ваш действующий сайт</strong>, чтобы унаследовать ваши настоящие шрифты, цвета и тон — самый быстрый путь к результату в духе бренда.</li>\n<li><strong>Используйте настольное приложение</strong> для пути без настройки; оно автоматически обнаруживает вашего агента.</li>\n<li><strong>Запускайте на вашей собственной подписке CLI</strong>, чтобы обойти отдельный недельный лимит на дизайн у закрытых инструментов.</li>\n<li><strong>Прочитайте сгенерированные <code>brand-spec.md</code> / <code>DESIGN.md</code></strong> — это редактируемые файлы, так что исправьте всё, что выборка распознала неверно.</li>\n<li><strong>Уделите немного внимания промпту</strong> — более насыщенный бриф даёт заметно лучший первый результат.</li>\n</ul>\n<h2 id=\"faq\">ЧаВо</h2>\n<p><strong>Действительно ли он может проектировать на основе моего существующего сайта?</strong>\nДа — у агента есть инструмент веб-выборки. Скажите ему проектировать для вашего сайта, и он считает ваши шрифты, цвета, решения по компоновке и тон в <code>brand-spec.md</code>, а затем спроектирует в этом стиле.</p>\n<p><strong>Нужно ли мне настраивать моего агента?</strong>\nОбычно нет. Настольное приложение автоматически обнаруживает уже установленные CLI агентов (Claude Code, Codex, Gemini и другие). Вы также можете подключить собственный ключ.</p>\n<p><strong>Есть ли у него лимиты использования закрытого инструмента?</strong>\nНикакого отдельного лимита на дизайн — генерация идёт через тот агент/подписку, что вы подключаете, поэтому вы не блокируетесь после одного дизайна.</p>\n<p><strong>Это бесплатно?</strong>\nПриложение — открытый исходный код под лицензией Apache-2.0, и запускать его локально бесплатно. Вы платите только за использование модели и медиа того агента и тех поставщиков, которых подключаете.</p>\n<hr>\n<p><em>Это текстовое руководство основано на разборе Brendan O'Connell. Посмотрите полное видео выше и <a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">подпишитесь на Brendan O'Connell</a>, чтобы получать больше разборов инструментов с открытым исходным кодом.</em></p>",
  },
  "es": {
    title: "Diseña con Open Design un sitio acorde con tu marca actual",
    summary: "Una guía práctica del truco estrella de Open Design: apúntalo a tu sitio web en vivo y el agente extrae tus tipografías, colores y tono en una especificación de marca y, luego, diseña con tu voz. Incluye la instalación de escritorio en un clic y una opinión sincera sobre los límites de uso de Claude Design. Basada en el recorrido de Brendan O'Connell.",
    bodyHtml: "<p>Esta guía se centra en un truco estrella de Open Design: <strong>apúntalo a tu sitio web existente y el agente extrae tu marca real —tipografías, colores, tono— en una especificación y, luego, diseña con tu voz.</strong> También cubre la instalación de escritorio en un clic y una mirada sincera al porqué de recurrir a una alternativa abierta. Sigue la construcción práctica que <strong>Brendan O'Connell</strong> realiza en <a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">su recorrido</a>, reescrita y actualizada a la versión actual. Mira el video de arriba para ver la ejecución en vivo, o sigue leyendo para la versión escrita.</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/generated-prototype.webp\" alt=\"Un prototipo real generado en Open Design.\">\n<em>Un prototipo real generado, renderizado en la vista previa: una landing page de agencia oscura y cinematográfica.</em></p>\n<h2 id=\"what-is-open-design\">¿Qué es Open Design?</h2>\n<p>Open Design es una plataforma de diseño de código abierto y local-first que se ejecuta <strong>sobre el agente de programación que ya usas</strong> —Claude Code, Codex, Cursor, Gemini, OpenCode y más— o con tu propia clave de API. En esencia es un espacio de trabajo al estilo de Claude Design que ejecutas en tu propia máquina, sin quedar atado a la nube de un solo proveedor ni sujeto a los topes de uso de esa herramienta. Es Apache-2.0, viene con una amplia biblioteca de skills y sistemas de diseño, y añade encima generación de medios (imagen, video, audio).</p>\n<h2 id=\"why-reach-for-an-open-alternative\">Por qué recurrir a una alternativa abierta</h2>\n<p>La motivación de Brendan es concreta y vale la pena repetirla porque, para mucha gente, es el factor decisivo. Generó un <em>único</em> sistema de diseño en la herramienta cerrada en la nube y se comió <strong>~75 % de su límite semanal</strong>, dejándolo atascado hasta la semana siguiente. Ese límite es independiente del cupo normal del plan, lo que hace que el flujo de trabajo resulte casi inutilizable para iterar de verdad. Ejecutarlo sobre tu propia suscripción de Claude Code (o cualquiera) elimina ese muro: no chocas con un tope de diseño aparte y no quedas encerrado en un solo ecosistema.</p>\n<h2 id=\"step-1--install-the-one-click-path\">Paso 1 — Instalar (la vía de un clic)</h2>\n<p>La ruta más fácil, y la que recomienda Brendan, es la <strong>aplicación de escritorio</strong>: ve a <a href=\"https://open-design.ai/download\">open-design.ai/download</a> y consigue el ejecutable para macOS o Windows. La app está en marcha en poco tiempo y <strong>detecta automáticamente los CLI de agentes que ya tienes en tu máquina</strong>: Brendan no configuró nada; reconoció su suscripción de Claude Code y quedó listo para usarse.</p>\n<p>¿Prefieres la terminal? Desde el código fuente:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Abre la URL local que imprime (un puerto dinámico: no lo fijes en duro). A la derecha encontrarás los ajustes: los agentes detectados, además de <strong>proveedores de medios</strong> (OpenAI para imagen, MiniMax para video, ElevenLabs para voz), conectores (Composio MCP) e incluso mascotas de escritorio. También puedes aportar tu propia clave para cualquier proveedor.</p>\n<h2 id=\"step-2--design-from-your-existing-brand\">Paso 2 — Diseñar a partir de tu marca existente</h2>\n<p>Este es el truco que vale por sí solo la entrada. Crea un proyecto, elige <strong>alta fidelidad</strong> y, en tu brief, dile que diseñe <em>para tu sitio existente</em>. El agente tiene una <strong>herramienta de obtención web</strong>, así que irá a leer tu sitio en vivo y luego derivará de él una especificación de marca.</p>\n<p>En el video, Brendan lo apunta a su propio sitio y Open Design:</p>\n<ol>\n<li><strong>Obtiene la página</strong> y extrae el contenido real.</li>\n<li><strong>Escribe un <code>brand-spec.md</code></strong> que captura su tipografía real (reconoció correctamente Fig Tree), su color y sus decisiones de diseño —«sin botones tipo píldora, sin tarjetas totalmente redondeadas, color de acento usado con moderación, espacios en blanco generosos»— además de su tono de voz («nada de marketing efusivo»).</li>\n<li><strong>Genera un <code>DESIGN.md</code></strong> y construye la página con esa voz, combinando su marca existente con una maquetación más limpia.</li>\n</ol>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/workspace-home.webp\" alt=\"El espacio de trabajo de Open Design: describe lo que quieres y elige un modo.\">\n<em>El espacio de trabajo de Open Design: describe lo que quieres crear, elige un modo y tu agente hace el resto.</em></p>\n<p>Antes de construir, Open Design ejecuta un breve <strong>formulario de descubrimiento</strong> (¿una página o unas pocas? ¿dirección visual? ¿coincidir con el sitio actual? ¿marcadores de posición realistas?) para fijar la dirección correcta. El resultado conserva su eslogan, su azul y su tipografía, y encima superpone una maquetación más nítida: una salida de varias páginas por las que puedes navegar haciendo clic.</p>\n<h2 id=\"step-3--review-the-anti-slop-self-check-and-export\">Paso 3 — Revisar la autocomprobación anti-slop y exportar</h2>\n<p>Al terminar, Open Design ejecuta una <strong>autocomprobación anti-slop</strong>: Brendan la ve confirmar «sin emojis, una sola tipografía, un detalle decisivo, texto de posicionamiento real de principio a fin». Esa es la barrera que evita que el resultado parezca generado.</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/motion-gallery.webp\" alt=\"La galería de motion y vídeo HyperFrames en Open Design.\">\n<em>La galería HyperFrames: piezas de motion y vídeo impulsadas por código que puedes forkear y remezclar.</em></p>\n<p>Recorre las pestañas <strong>ejemplos</strong> y <strong>sistemas de diseño</strong> en busca de puntos de partida (cada sistema de diseño te da un <code>DESIGN.md</code> totalmente editable) y, cuando estés conforme, exporta el artefacto como HTML, PDF o un ZIP. Como todo se ejecuta localmente en tu propio agente, no hay un tope de diseño aparte con el que chocar mientras iteras.</p>\n<h2 id=\"tips\">Consejos</h2>\n<ul>\n<li><strong>Apúntalo a tu sitio en vivo</strong> para heredar tus tipografías, colores y tono reales: la vía más rápida hacia un resultado fiel a la marca.</li>\n<li><strong>Usa la aplicación de escritorio</strong> para la vía sin configuración; detecta tu agente automáticamente.</li>\n<li><strong>Ejecútalo con tu propia suscripción de CLI</strong> para esquivar el tope semanal de diseño aparte de las herramientas cerradas.</li>\n<li><strong>Lee los <code>brand-spec.md</code> / <code>DESIGN.md</code> generados</strong>: son archivos editables, así que corrige cualquier cosa que la extracción haya captado mal.</li>\n<li><strong>Invierte un poco en el prompt</strong>: un brief más rico produce una primera versión notablemente mejor.</li>\n</ul>\n<h2 id=\"faq\">Preguntas frecuentes</h2>\n<p><strong>¿De verdad puede diseñar a partir de mi sitio web existente?</strong>\nSí: el agente tiene una herramienta de obtención web. Dile que diseñe para tu sitio y extraerá tus tipografías, colores, decisiones de maquetación y tono en un <code>brand-spec.md</code>, y luego diseñará con esa voz.</p>\n<p><strong>¿Tengo que configurar mi agente?</strong>\nNormalmente no. La aplicación de escritorio detecta automáticamente los CLI de agentes ya instalados (Claude Code, Codex, Gemini y más). También puedes aportar tu propia clave.</p>\n<p><strong>¿Tiene los límites de uso de la herramienta cerrada?</strong>\nNo hay un tope de diseño aparte: la generación va sobre el agente/suscripción que conectes, así que no te bloquean tras un solo diseño.</p>\n<p><strong>¿Es gratis?</strong>\nLa app es de código abierto bajo Apache-2.0 y gratuita para ejecutar localmente. Solo pagas por el uso de modelo y medios del agente y los proveedores que conectes.</p>\n<hr>\n<p><em>Esta guía escrita se basa en el recorrido de Brendan O'Connell. Mira el video completo de arriba y <a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">suscríbete a Brendan O'Connell</a> para más análisis de herramientas de código abierto.</em></p>",
  },
  "pt-br": {
    title: "Projete com o Open Design um site que combina com sua marca atual",
    summary: "Um guia prático do truque de destaque do Open Design — aponte-o para o seu site no ar e o agente extrai suas fontes, cores e tom em uma especificação de marca e, então, projeta na sua voz. Inclui a instalação desktop em um clique e uma avaliação franca sobre os limites de uso do Claude Design. Baseado no passo a passo de Brendan O'Connell.",
    bodyHtml: "<p>Este guia foca em um truque de destaque do Open Design: <strong>aponte-o para o seu site existente e o agente puxa a sua marca real — fontes, cores, tom — para uma especificação e, então, projeta na sua voz.</strong> Ele também cobre a instalação desktop em um clique e uma leitura franca sobre por que recorrer a uma alternativa aberta. Segue a construção prática que <strong>Brendan O'Connell</strong> conduz em <a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">seu passo a passo</a>, reescrita e atualizada para a versão atual. Assista ao vídeo acima para ver a execução ao vivo, ou continue lendo para a versão escrita.</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/generated-prototype.webp\" alt=\"Um protótipo real gerado no Open Design.\">\n<em>Um protótipo real gerado, renderizado na pré-visualização — uma landing page de agência escura e cinematográfica.</em></p>\n<h2 id=\"what-is-open-design\">O que é o Open Design?</h2>\n<p>O Open Design é uma plataforma de design de código aberto e local-first que roda <strong>sobre o agente de programação que você já usa</strong> — Claude Code, Codex, Cursor, Gemini, OpenCode e mais — ou com a sua própria chave de API. É, em essência, um espaço de trabalho no estilo do Claude Design que você executa na sua própria máquina, sem ficar preso à nuvem de um único fornecedor e sem os limites de uso daquela ferramenta. É Apache-2.0, vem com uma vasta biblioteca de skills e design systems e acrescenta por cima a geração de mídia (imagem, vídeo, áudio).</p>\n<h2 id=\"why-reach-for-an-open-alternative\">Por que recorrer a uma alternativa aberta</h2>\n<p>A motivação de Brendan é concreta e vale a pena repetir, porque é o fator decisivo para muita gente. Ele gerou um <em>único</em> design system na ferramenta fechada na nuvem e isso devorou <strong>~75% do seu limite semanal</strong> — deixando-o travado até a semana seguinte. Esse limite é separado da cota normal do plano, o que faz o fluxo de trabalho parecer quase inutilizável para uma iteração de verdade. Rodar na sua própria assinatura do Claude Code (ou qualquer outra) remove essa parede: você não esbarra num teto de design separado e não fica preso a um único ecossistema.</p>\n<h2 id=\"step-1--install-the-one-click-path\">Passo 1 — Instalar (o caminho de um clique)</h2>\n<p>A rota mais fácil, e a que Brendan recomenda, é o <strong>aplicativo desktop</strong>: vá até <a href=\"https://open-design.ai/download\">open-design.ai/download</a> e pegue o executável para macOS ou Windows. O app fica no ar em pouco tempo e <strong>detecta automaticamente os CLIs de agentes já presentes na sua máquina</strong> — Brendan não configurou nada; ele reconheceu a assinatura do Claude Code dele e ficou pronto para usar.</p>\n<p>Prefere o terminal? A partir do código-fonte:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Abra a URL local que ele imprime (uma porta dinâmica — não fixe nenhuma no código). À direita você encontrará as configurações: os agentes detectados, além de <strong>provedores de mídia</strong> (OpenAI para imagem, MiniMax para vídeo, ElevenLabs para voz), conectores (Composio MCP) e até bichinhos de desktop. Você também pode usar a sua própria chave para qualquer provedor.</p>\n<h2 id=\"step-2--design-from-your-existing-brand\">Passo 2 — Projetar a partir da sua marca existente</h2>\n<p>Este é o truque que sozinho já vale o preço do ingresso. Crie um projeto, escolha <strong>alta fidelidade</strong> e, no seu brief, diga a ele para projetar <em>para o seu site existente</em>. O agente tem uma <strong>ferramenta de busca na web</strong>, então ele vai ler o seu site no ar e, em seguida, derivar dele uma especificação de marca.</p>\n<p>No vídeo, Brendan o aponta para o próprio site e o Open Design:</p>\n<ol>\n<li><strong>Busca a página</strong> e extrai o conteúdo real.</li>\n<li><strong>Escreve um <code>brand-spec.md</code></strong> capturando a fonte real dele (reconheceu corretamente a Fig Tree), a cor dele e suas escolhas de design — \"sem botões em formato de pílula, sem cartões totalmente arredondados, cor de destaque usada com parcimônia, espaços em branco generosos\" — além do tom de voz (\"nada de marketing ofegante\").</li>\n<li><strong>Gera um <code>DESIGN.md</code></strong> e constrói a página naquela voz, mesclando a marca existente dele com um layout mais limpo.</li>\n</ol>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/workspace-home.webp\" alt=\"O espaço de trabalho do Open Design — descreva o que você quer e escolha um modo.\">\n<em>O espaço de trabalho do Open Design: descreva o que você quer criar, escolha um modo e seu agente faz o resto.</em></p>\n<p>Antes de construir, o Open Design roda um breve <strong>formulário de descoberta</strong> (uma página ou algumas páginas? direção visual? combinar com o site atual? espaços reservados realistas?) para travar a direção certa. O resultado mantém o slogan dele, o azul dele e a fonte dele e, por cima, sobrepõe um layout mais nítido — uma saída de várias páginas pelas quais você pode navegar clicando.</p>\n<h2 id=\"step-3--review-the-anti-slop-self-check-and-export\">Passo 3 — Revisar a autoverificação anti-slop e exportar</h2>\n<p>Ao concluir, o Open Design roda uma <strong>autoverificação anti-slop</strong> — Brendan a vê confirmar \"sem emojis, uma tipografia, um floreio decisivo, texto de posicionamento real do começo ao fim\". Essa é a barreira de proteção que impede que o resultado pareça gerado.</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/motion-gallery.webp\" alt=\"A galeria de motion e vídeo HyperFrames no Open Design.\">\n<em>A galeria HyperFrames: peças de motion e vídeo orientadas por código que você pode forkar e remixar.</em></p>\n<p>Navegue pelas abas <strong>exemplos</strong> e <strong>design systems</strong> em busca de pontos de partida (cada design system te dá um <code>DESIGN.md</code> totalmente editável) e, quando estiver satisfeito, exporte o artefato como HTML, PDF ou um ZIP. Como tudo roda localmente no seu próprio agente, não há um teto de design separado para esbarrar enquanto você itera.</p>\n<h2 id=\"tips\">Dicas</h2>\n<ul>\n<li><strong>Aponte-o para o seu site no ar</strong> para herdar suas fontes, cores e tom reais — o caminho mais rápido para um resultado fiel à marca.</li>\n<li><strong>Use o aplicativo desktop</strong> para o caminho sem configuração; ele detecta o seu agente automaticamente.</li>\n<li><strong>Rode na sua própria assinatura de CLI</strong> para escapar do teto semanal de design separado das ferramentas fechadas.</li>\n<li><strong>Leia os <code>brand-spec.md</code> / <code>DESIGN.md</code> gerados</strong> — são arquivos editáveis, então corrija qualquer coisa que a extração tenha captado errado.</li>\n<li><strong>Invista um pouco no prompt</strong> — um brief mais rico produz uma primeira versão visivelmente melhor.</li>\n</ul>\n<h2 id=\"faq\">Perguntas frequentes</h2>\n<p><strong>Ele realmente consegue projetar a partir do meu site existente?</strong>\nSim — o agente tem uma ferramenta de busca na web. Diga a ele para projetar para o seu site e ele extrai suas fontes, cores, escolhas de layout e tom para um <code>brand-spec.md</code> e, então, projeta naquela voz.</p>\n<p><strong>Eu preciso configurar o meu agente?</strong>\nGeralmente não. O aplicativo desktop detecta automaticamente os CLIs de agentes já instalados (Claude Code, Codex, Gemini e mais). Você também pode usar a sua própria chave.</p>\n<p><strong>Ele tem os limites de uso da ferramenta fechada?</strong>\nNenhum teto de design separado — a geração depende de qualquer agente/assinatura que você conectar, então você não fica bloqueado depois de um único design.</p>\n<p><strong>É grátis?</strong>\nO app é de código aberto sob a Apache-2.0 e gratuito para rodar localmente. Você só paga pelo uso de modelo e mídia de qualquer agente e provedores que conectar.</p>\n<hr>\n<p><em>Este guia escrito é baseado no passo a passo de Brendan O'Connell. Assista ao vídeo completo acima e <a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">inscreva-se no canal de Brendan O'Connell</a> para mais análises de ferramentas de código aberto.</em></p>",
  },
  "it": {
    title: "Progetta con Open Design un sito in linea con il tuo brand esistente",
    summary: "Una guida pratica al trucco di punta di Open Design: puntalo al tuo sito web live e l'agente raccoglie i tuoi font, colori e tono in una specifica di brand, poi progetta con la tua voce. Include l'installazione desktop in un clic e un giudizio sincero sui limiti d'uso di Claude Design. Basata sul tutorial di Brendan O'Connell.",
    bodyHtml: "<p>Questa guida si concentra su un trucco di punta di Open Design: <strong>puntalo al tuo sito esistente e l'agente estrae il tuo vero brand — font, colori, tono — in una specifica, poi progetta con la tua voce.</strong> Copre anche l'installazione desktop in un clic e una lettura sincera del perché rivolgersi a un'alternativa aperta. Segue la costruzione pratica che <strong>Brendan O'Connell</strong> realizza nel <a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">suo tutorial</a>, riscritta e aggiornata alla versione attuale. Guarda il video qui sopra per l'esecuzione dal vivo, oppure prosegui con la versione scritta.</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/generated-prototype.webp\" alt=\"Un vero prototipo generato in Open Design.\">\n<em>Un vero prototipo generato, mostrato nell'anteprima: una landing page d'agenzia scura e cinematografica.</em></p>\n<h2 id=\"what-is-open-design\">Cos'è Open Design?</h2>\n<p>Open Design è una piattaforma di design open source e local-first che gira <strong>sopra l'agente di codice che già usi</strong> — Claude Code, Codex, Cursor, Gemini, OpenCode e altri — o con la tua chiave API. È in sostanza un'area di lavoro in stile Claude Design che esegui sulla tua macchina, senza restare vincolato al cloud di un singolo fornitore e senza i tetti d'uso di quello strumento. È Apache-2.0, arriva con un'ampia libreria di skill e design system e ci aggiunge sopra la generazione di media (immagini, video, audio).</p>\n<h2 id=\"why-reach-for-an-open-alternative\">Perché rivolgersi a un'alternativa aperta</h2>\n<p>La motivazione di Brendan è concreta e vale la pena ripeterla perché, per molti, è il fattore decisivo. Ha generato un <em>singolo</em> design system nello strumento cloud chiuso e si è mangiato <strong>circa il 75% del suo limite settimanale</strong> — lasciandolo bloccato fino alla settimana successiva. Quel limite è separato dalla normale quota del piano, il che rende il flusso di lavoro al limite dell'inutilizzabile per un'iterazione reale. Eseguirlo sul tuo abbonamento Claude Code (o qualunque altro) abbatte quel muro: non sbatti contro un tetto di design separato e non resti chiuso in un solo ecosistema.</p>\n<h2 id=\"step-1--install-the-one-click-path\">Passo 1 — Installa (la via in un clic)</h2>\n<p>La strada più semplice, e quella che Brendan consiglia, è l'<strong>app desktop</strong>: vai su <a href=\"https://open-design.ai/download\">open-design.ai/download</a> e scarica l'eseguibile per macOS o Windows. L'app è operativa in poco tempo e <strong>rileva automaticamente le CLI degli agenti già presenti sulla tua macchina</strong> — Brendan non ha configurato nulla; ha riconosciuto il suo abbonamento Claude Code ed era pronta all'uso.</p>\n<p>Preferisci il terminale? Dai sorgenti:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Apri l'URL locale che stampa (una porta dinamica — non fissarne una nel codice). Sulla destra trovi le impostazioni: gli agenti rilevati, oltre ai <strong>provider di media</strong> (OpenAI per le immagini, MiniMax per i video, ElevenLabs per la voce), i connettori (Composio MCP) e perfino i pet da desktop. Puoi anche usare la tua chiave per qualsiasi provider.</p>\n<h2 id=\"step-2--design-from-your-existing-brand\">Passo 2 — Progettare a partire dal tuo brand esistente</h2>\n<p>Questo è il trucco che da solo vale il prezzo del biglietto. Crea un progetto, scegli <strong>alta fedeltà</strong> e, nel tuo brief, digli di progettare <em>per il tuo sito esistente</em>. L'agente dispone di uno <strong>strumento di recupero web</strong>, quindi andrà a leggere il tuo sito live e ne ricaverà una specifica di brand.</p>\n<p>Nel video, Brendan lo punta al proprio sito e Open Design:</p>\n<ol>\n<li><strong>Recupera la pagina</strong> ed estrae i contenuti reali.</li>\n<li><strong>Scrive un <code>brand-spec.md</code></strong> che cattura il suo font reale (ha riconosciuto correttamente Fig Tree), il suo colore e le sue scelte di design — «niente pulsanti a pillola, niente card completamente arrotondate, colore d'accento usato con parsimonia, spazi bianchi generosi» — oltre al suo tono di voce («niente marketing trafelato»).</li>\n<li><strong>Genera un <code>DESIGN.md</code></strong> e costruisce la pagina con quella voce, fondendo il suo brand esistente con un layout più pulito.</li>\n</ol>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/workspace-home.webp\" alt=\"L'area di lavoro di Open Design: descrivi ciò che vuoi e scegli una modalità.\">\n<em>L'area di lavoro di Open Design: descrivi ciò che vuoi creare, scegli una modalità e il tuo agente fa il resto.</em></p>\n<p>Prima di costruire, Open Design esegue un breve <strong>modulo di discovery</strong> (una sola pagina o qualche pagina? direzione visiva? combaciare con il sito attuale? segnaposto realistici?) così da bloccare la direzione giusta. Il risultato conserva il suo slogan, il suo blu e il suo font, poi vi sovrappone un layout più incisivo — un output multipagina che puoi sfogliare cliccando.</p>\n<h2 id=\"step-3--review-the-anti-slop-self-check-and-export\">Passo 3 — Rivedere l'autocontrollo anti-slop ed esportare</h2>\n<p>Mentre conclude, Open Design esegue un <strong>autocontrollo anti-slop</strong> — Brendan lo vede confermare «niente emoji, un solo carattere, un tocco decisivo, testi di posizionamento reali ovunque». È la barriera che impedisce all'output di sembrare generato.</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/motion-gallery.webp\" alt=\"La galleria di motion e video HyperFrames in Open Design.\">\n<em>La galleria HyperFrames: contenuti di motion e video guidati dal codice, da forkare e remixare.</em></p>\n<p>Sfoglia le schede <strong>esempi</strong> e <strong>design system</strong> per trovare punti di partenza (ogni design system ti dà un <code>DESIGN.md</code> completamente modificabile) e, quando sei soddisfatto, esporta l'artefatto come HTML, PDF o uno ZIP. Poiché tutto gira localmente sul tuo agente, non c'è alcun tetto di design separato contro cui sbattere mentre iteri.</p>\n<h2 id=\"tips\">Consigli</h2>\n<ul>\n<li><strong>Puntalo al tuo sito live</strong> per ereditare i tuoi font, colori e tono reali — la via più rapida a un risultato fedele al brand.</li>\n<li><strong>Usa l'app desktop</strong> per la via senza configurazione; rileva il tuo agente automaticamente.</li>\n<li><strong>Esegui sul tuo abbonamento CLI</strong> per schivare il tetto settimanale di design separato degli strumenti chiusi.</li>\n<li><strong>Leggi i <code>brand-spec.md</code> / <code>DESIGN.md</code> generati</strong> — sono file modificabili, quindi correggi tutto ciò che l'estrazione ha colto in modo errato.</li>\n<li><strong>Investi un po' nel prompt</strong> — un brief più ricco produce una prima bozza nettamente migliore.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Può davvero progettare a partire dal mio sito esistente?</strong>\nSì — l'agente ha uno strumento di recupero web. Digli di progettare per il tuo sito ed estrarrà i tuoi font, colori, scelte di layout e tono in un <code>brand-spec.md</code>, poi progetterà con quella voce.</p>\n<p><strong>Devo configurare il mio agente?</strong>\nDi solito no. L'app desktop rileva automaticamente le CLI degli agenti già installate (Claude Code, Codex, Gemini e altri). Puoi anche usare la tua chiave.</p>\n<p><strong>Ha i limiti d'uso dello strumento chiuso?</strong>\nNessun tetto di design separato — la generazione si appoggia a qualunque agente/abbonamento colleghi, quindi non vieni bloccato dopo un solo design.</p>\n<p><strong>È gratis?</strong>\nL'app è open source sotto Apache-2.0 e gratuita da eseguire localmente. Paghi soltanto l'uso di modello e media dell'agente e dei provider che colleghi.</p>\n<hr>\n<p><em>Questa guida scritta è basata sul tutorial di Brendan O'Connell. Guarda il video completo qui sopra e <a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">iscriviti al canale di Brendan O'Connell</a> per altre analisi di strumenti open source.</em></p>",
  },
  "tr": {
    title: "Open Design ile Mevcut Markanıza Uyan Bir Site Tasarlayın",
    summary: "Open Design'ın öne çıkan numarasına dair uygulamalı bir kılavuz — onu canlı web sitenize yönlendirin, ajan yazı tiplerinizi, renklerinizi ve tonunuzu bir marka spesifikasyonuna kazısın, sonra sizin sesinizle tasarlasın. Tek tıkla masaüstü kurulumunu ve Claude Design'ın kullanım limitlerine dair dürüst bir değerlendirmeyi içerir. Brendan O'Connell'ın anlatımına dayanır.",
    bodyHtml: "<p>Bu kılavuz, Open Design'ın öne çıkan bir numarasına odaklanır: <strong>onu mevcut web sitenize yönlendirin, ajan gerçek markanızı — yazı tipleri, renkler, ton — bir spesifikasyona çeksin, sonra sizin sesinizle tasarlasın.</strong> Ayrıca tek tıkla masaüstü kurulumunu ve neden açık bir alternatife yöneleceğinize dair dürüst bir bakışı da ele alır. <strong>Brendan O'Connell</strong>'ın <a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">anlatımında</a> yürüttüğü uygulamalı yapımı izler; yeniden yazılmış ve güncel sürüme göre güncellenmiştir. Canlı çalıştırma için yukarıdaki videoyu izleyin ya da yazılı sürüm için okumaya devam edin.</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/generated-prototype.webp\" alt=\"Open Design'da üretilen gerçek bir prototip.\">\n<em>Önizlemede gösterilen gerçek bir üretilmiş prototip — koyu, sinematik bir ajans açılış sayfası.</em></p>\n<h2 id=\"what-is-open-design\">Open Design nedir?</h2>\n<p>Open Design, <strong>zaten kullandığınız kodlama ajanının üzerinde çalışan</strong> — Claude Code, Codex, Cursor, Gemini, OpenCode ve daha fazlası — ya da kendi API anahtarınızla çalışan, açık kaynaklı ve yerel öncelikli bir tasarım platformudur. Esasında, tek bir tedarikçinin bulutuna kilitlenmeden ve o aracın kullanım tavanları olmadan kendi makinenizde çalıştırdığınız Claude-Design tarzı bir çalışma alanıdır. Apache-2.0 lisanslıdır, kapsamlı bir beceri ve tasarım sistemi kütüphanesiyle gelir ve bunun üstüne medya üretimi (görsel, video, ses) ekler.</p>\n<h2 id=\"why-reach-for-an-open-alternative\">Neden açık bir alternatife yönelmeli</h2>\n<p>Brendan'ın gerekçesi somut ve tekrar etmeye değer, çünkü birçok kişi için belirleyici etken bu. Kapalı bulut aracında <em>tek bir</em> tasarım sistemi üretti ve bu, <strong>haftalık limitinin yaklaşık %75'ini</strong> yiyip bitirdi — onu sonraki haftaya kadar tıkanmış bıraktı. Bu limit, normal plan kotasından ayrıdır; bu da iş akışını gerçek bir yineleme için neredeyse kullanılamaz hissettirir. Kendi Claude Code (ya da herhangi bir) aboneliğinizde çalıştırmak bu duvarı kaldırır: ayrı bir tasarım tavanına çarpmazsınız ve tek bir ekosisteme kilitlenmezsiniz.</p>\n<h2 id=\"step-1--install-the-one-click-path\">Adım 1 — Kurulum (tek tıkla yol)</h2>\n<p>En kolay rota ve Brendan'ın önerdiği, <strong>masaüstü uygulamasıdır</strong>: <a href=\"https://open-design.ai/download\">open-design.ai/download</a> adresine gidip macOS veya Windows için çalıştırılabilir dosyayı edinin. Uygulama kısa sürede çalışır hale gelir ve <strong>makinenizde halihazırda bulunan ajan CLI'larını otomatik olarak algılar</strong> — Brendan hiçbir şey yapılandırmadı; Claude Code aboneliğini yakaladı ve kullanıma hazırdı.</p>\n<p>Terminali mi tercih edersiniz? Kaynaktan:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Yazdırdığı yerel URL'yi açın (dinamik bir bağlantı noktası — hiçbirini sabit kodlamayın). Sağda ayarları bulacaksınız: algılanan ajanların yanı sıra <strong>medya sağlayıcıları</strong> (görsel için OpenAI, video için MiniMax, ses için ElevenLabs), bağlayıcılar (Composio MCP) ve hatta masaüstü evcil hayvanları. Herhangi bir sağlayıcı için kendi anahtarınızı da getirebilirsiniz.</p>\n<h2 id=\"step-2--design-from-your-existing-brand\">Adım 2 — Mevcut markanızdan tasarlayın</h2>\n<p>İşte bilet parasına değen numara bu. Bir proje oluşturun, <strong>yüksek doğruluk</strong> seçin ve brief'inizde ona <em>mevcut siteniz için</em> tasarlamasını söyleyin. Ajanın bir <strong>web getirme aracı</strong> var, bu yüzden gidip canlı web sitenizi okuyacak, ardından ondan bir marka spesifikasyonu çıkaracak.</p>\n<p>Videoda Brendan onu kendi sitesine yönlendiriyor ve Open Design:</p>\n<ol>\n<li><strong>Sayfayı getiriyor</strong> ve gerçek içeriği kazıyor.</li>\n<li><strong>Bir <code>brand-spec.md</code> yazıyor</strong>; gerçek yazı tipini (Fig Tree'yi doğru şekilde yakaladı), rengini ve tasarım tercihlerini — \"hap biçimli düğme yok, tamamen yuvarlatılmış kart yok, vurgu rengi idareli kullanılmış, bol beyaz alan\" — ayrıca ses tonunu (\"soluk soluğa pazarlama yok\") kaydediyor.</li>\n<li><strong>Bir <code>DESIGN.md</code> üretiyor</strong> ve sayfayı o sesle inşa ediyor; mevcut markasını daha temiz bir düzenle harmanlıyor.</li>\n</ol>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/workspace-home.webp\" alt=\"Open Design çalışma alanı — ne istediğinizi anlatın ve bir mod seçin.\">\n<em>Open Design çalışma alanı: oluşturmak istediğinizi anlatın, bir mod seçin, gerisini ajanınız halletsin.</em></p>\n<p>İnşa etmeden önce Open Design kısa bir <strong>keşif formu</strong> çalıştırır (tek sayfa mı yoksa birkaç sayfa mı? görsel yön? mevcut siteyle eşleşsin mi? gerçekçi yer tutucular mı?) ki doğru yönü sabitlesin. Sonuç, onun sloganını, mavisini ve yazı tipini korur, sonra üstüne daha keskin bir düzen kaplar — tıklayarak gezebileceğiniz çok sayfalı bir çıktı.</p>\n<h2 id=\"step-3--review-the-anti-slop-self-check-and-export\">Adım 3 — Anti-slop öz denetimini gözden geçirin ve dışa aktarın</h2>\n<p>Bitirirken Open Design bir <strong>anti-slop öz denetimi</strong> çalıştırır — Brendan bunun \"emoji yok, tek yazı tipi, tek kararlı dokunuş, baştan sona gerçek konumlandırma metni\" diye onayladığını görür. Çıktının üretilmiş gibi görünmesini engelleyen koruyucu bariyer budur.</p>\n<p><img src=\"/tutorials/open-design-claude-design-alternative-open-source-brendan-o-connell/motion-gallery.webp\" alt=\"Open Design'daki HyperFrames hareket ve video galerisi.\">\n<em>HyperFrames galerisi: fork'layıp yeniden düzenleyebileceğiniz, kodla yönlendirilen hareket ve video çalışmaları.</em></p>\n<p>Başlangıç noktaları için <strong>örnekler</strong> ve <strong>tasarım sistemleri</strong> sekmelerine göz atın (her tasarım sistemi size tümüyle düzenlenebilir bir <code>DESIGN.md</code> verir) ve memnun kaldığınızda eseri HTML, PDF veya bir ZIP olarak dışa aktarın. Her şey kendi ajanınızda yerel olarak çalıştığından, yineleme yaparken çarpacağınız ayrı bir tasarım tavanı yoktur.</p>\n<h2 id=\"tips\">İpuçları</h2>\n<ul>\n<li><strong>Onu canlı sitenize yönlendirin</strong> ki gerçek yazı tiplerinizi, renklerinizi ve tonunuzu devralsın — markaya uygun çıktıya giden en hızlı yol.</li>\n<li>Sıfır yapılandırma yolu için <strong>masaüstü uygulamasını kullanın</strong>; ajanınızı otomatik algılar.</li>\n<li>Kapalı araçların ayrı haftalık tasarım tavanından kaçınmak için <strong>kendi CLI aboneliğinizde çalıştırın</strong>.</li>\n<li>Üretilen <strong><code>brand-spec.md</code> / <code>DESIGN.md</code> dosyalarını okuyun</strong> — bunlar düzenlenebilir dosyalardır, dolayısıyla kazımanın yanlış aldığı her şeyi düzeltin.</li>\n<li><strong>Prompt'a biraz emek verin</strong> — daha zengin bir brief, gözle görülür şekilde daha iyi bir ilk taslak üretir.</li>\n</ul>\n<h2 id=\"faq\">SSS</h2>\n<p><strong>Gerçekten mevcut web sitemden tasarlayabilir mi?</strong>\nEvet — ajanın bir web getirme aracı var. Ona sitenize göre tasarlamasını söyleyin; yazı tiplerinizi, renklerinizi, düzen tercihlerinizi ve tonunuzu bir <code>brand-spec.md</code> dosyasına kazır, ardından o sesle tasarlar.</p>\n<p><strong>Ajanımı yapılandırmam gerekir mi?</strong>\nGenellikle hayır. Masaüstü uygulaması, halihazırda yüklü ajan CLI'larını (Claude Code, Codex, Gemini ve daha fazlası) otomatik algılar. Kendi anahtarınızı da getirebilirsiniz.</p>\n<p><strong>Kapalı aracın kullanım limitleri onda da var mı?</strong>\nAyrı bir tasarım tavanı yok — üretim, bağladığınız hangi ajan/abonelikse onun üzerinden gider, dolayısıyla tek bir tasarımdan sonra engellenmezsiniz.</p>\n<p><strong>Ücretsiz mi?</strong>\nUygulama Apache-2.0 altında açık kaynaktır ve yerel olarak çalıştırmak ücretsizdir. Yalnızca bağladığınız ajan ve sağlayıcıların model ve medya kullanımı için ödersiniz.</p>\n<hr>\n<p><em>Bu yazılı kılavuz Brendan O'Connell'ın anlatımına dayanır. Yukarıdaki tam videoyu izleyin ve daha fazla açık kaynak araç incelemesi için <a href=\"https://www.youtube.com/watch?v=DVoIj1Aa88I\">Brendan O'Connell'a abone olun</a>.</em></p>",
  },
};
